import React, { useEffect, useState } from "react";

function App() {
  const [questions, setQuestions] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState("");
  const [result, setResult] = useState("");
  const [score, setScore] = useState(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("http://localhost:5000/api/games")
      .then((res) => res.json())
      .then((data) => {
        setQuestions(data);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error fetching questions:", err);
        setLoading(false);
      });
  }, []);

  const handleAnswerClick = (option) => {
    if (!questions[currentIndex]) return;

    setSelectedAnswer(option);

    if (option === questions[currentIndex].correctAnswer) {
      setResult("Correct Answer");
      setScore(score + 10);
    } else {
      setResult(`Wrong Answer. Correct answer: ${questions[currentIndex].correctAnswer}`);
    }
  };

  const handleNextQuestion = () => {
    setSelectedAnswer("");
    setResult("");

    if (currentIndex < questions.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      setResult("Quiz Completed");
    }
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <h2>Loading questions...</h2>
      </div>
    );
  }

  if (questions.length === 0) {
    return (
      <div style={styles.container}>
        <h2>No questions found in database</h2>
      </div>
    );
  }

  const currentQuestion = questions[currentIndex];

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.heading}>Quiz Game</h1>

        <p style={styles.score}>Score: {score}</p>

        {currentIndex < questions.length ? (
          <>
            <h2 style={styles.question}>
              Q{currentIndex + 1}. {currentQuestion.question}
            </h2>

            <div style={styles.optionsContainer}>
              {currentQuestion.options.map((option, index) => (
                <button
                  key={index}
                  onClick={() => handleAnswerClick(option)}
                  disabled={selectedAnswer !== ""}
                  style={{
                    ...styles.optionButton,
                    backgroundColor:
                      selectedAnswer === option ? "#d1e7dd" : "#f8f9fa",
                  }}
                >
                  {option}
                </button>
              ))}
            </div>

            {result && <p style={styles.result}>{result}</p>}

            {selectedAnswer && (
              <button onClick={handleNextQuestion} style={styles.nextButton}>
                {currentIndex === questions.length - 1 ? "Finish Quiz" : "Next Question"}
              </button>
            )}
          </>
        ) : (
          <>
            <h2 style={styles.finalText}>Quiz Completed</h2>
            <p style={styles.finalScore}>Final Score: {score}</p>
          </>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: {
    minHeight: "100vh",
    backgroundColor: "#f4f6f8",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },
  card: {
    backgroundColor: "#ffffff",
    padding: "30px",
    borderRadius: "12px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    width: "100%",
    maxWidth: "600px",
    textAlign: "center",
  },
  heading: {
    marginBottom: "20px",
    color: "#333",
  },
  score: {
    fontSize: "18px",
    fontWeight: "bold",
    marginBottom: "20px",
    color: "#007bff",
  },
  question: {
    marginBottom: "20px",
    color: "#222",
  },
  optionsContainer: {
    display: "flex",
    flexDirection: "column",
    gap: "12px",
  },
  optionButton: {
    padding: "12px",
    fontSize: "16px",
    borderRadius: "8px",
    border: "1px solid #ccc",
    cursor: "pointer",
  },
  result: {
    marginTop: "20px",
    fontWeight: "bold",
    color: "#28a745",
  },
  nextButton: {
    marginTop: "20px",
    padding: "12px 20px",
    backgroundColor: "#007bff",
    color: "#fff",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "16px",
  },
  finalText: {
    color: "#28a745",
  },
  finalScore: {
    fontSize: "22px",
    fontWeight: "bold",
    color: "#007bff",
  },
};

export default App;
